  ('heelevel3-988e0de1-moex-00140', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '乙國稅局課徵遺產稅於 108 年底取得抵繳實物股票抵繳已認列之應收稅款，帳面值計 10 萬元， 嗣於次年將該股票變現繳庫8萬元，則下列變現繳庫時之會計分錄何者正確？', '["借記繳付公庫數8萬元與借記應收稅款2萬元及貸記抵繳收入實物10萬元", "借記繳付公庫數8萬元及貸記抵繳收入實物8萬元", "借記繳付公庫數8萬元與借記淨資產2萬元及貸記抵繳收入實物10萬元", "借記繳付公庫數8萬元與借記稅課收入2萬元及貸記抵繳收入實物10萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00141', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依政府會計準則公報，下列關於配合原則之敘述，何者正確？①公立醫院將當年度提供醫療服務', '["政府在特定會計期間認列交易收入時， 應同時認列收入有關之支出", "公務機關應於罰款收現時認列收入", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00142', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '中央政府甲機關因109年度法定預算遲至109年1月1日尚未完成立法程序，爰其支付108年度 已在職員工之109年1月份薪資，其借方科目應以下列何者入帳？', '["預付款項", "人事支出", "應付款項", "繳付公庫數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00143', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '甲機關之固定資產遭遇毀損時，為沖銷其帳面金額，應借記那個會計科目？', '["固定資產折舊", "財產交易損失", "資本資產總額", "資產負債淨額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00144', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', 'X1年初中央政府甲機關持有A公司股權40%，該公司淨值80億元，已發行股數3億股，每股面 額10元，年度中甲機關以每股80元洽特定人出售半數持股。X3年度再於公開市場以每股90元 釋出剩餘持股之半數，此時公司淨值為120億元。下列甲機關對A公司投資會計處理之敘述，何 者正確？', '["X1年釋出持股後，具有重大影響力之情況，故無須改列其他長期投資，並按每股80元認列為 新成本", "X1年釋出持股後，不具有重大影響力之情況，故須改列其他長期投資，並按每股26.67元認列 為新成本", "X3年釋出持股後，不具有重大影響力之情況，故須改列其他長期投資，並按每股90元認列為 新成本", "X3年釋出持股後，不具有重大影響力之情況，故須改列其他長期投資，並按每股40元認列為 新成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00145', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'single_choice', '依據政府會計準則公報、中央總會計制度及中央政府普通公務單位會計制度之一致規定，對於作 業基金及國營事業改制之敘述，下列何者正確？', '["作業基金改制為國營事業後，將從其他長期投資改列為採權益法之投資", "作業基金改制為行政法人後，仍須納入中央政府總會計年度會計報告中", "中央政府對國營事業的持股比率一旦低於50%，將從採權益法之投資改列為其他長期投資", "作業基金改制為100%政府捐助財團法人後，仍維持帳列其他長期投資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "dcb3276a8393", "answer_pdf_sha1": "807ca00816e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
